from board import Board
from player import Player
import click
from colorama import Fore, Style, init

init(autoreset=True)

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player("white"), Player("black")]
        self.current_player = 0

    def run(self):
        while True:
            self.print_board()
            move = input(f"Player {self.players[self.current_player].color}'s turn. Enter your move (from-to): ")
            if move.lower() in ["exit", "quit"]:
                break
            try:
                from_pos, to_pos = map(int, move.split('-'))
                self.make_move(from_pos, to_pos)
            except ValueError:
                click.echo("Invalid move format. Please use 'from-to' notation.")
                continue
            if self.check_winner():
                click.echo(f"Player {self.players[self.current_player].color} wins!")
                break
            self.switch_turn()

    def print_board(self):
        for row in range(8):
            click.echo(' '.join([Fore.WHITE + piece.symbol if piece.color == "white" else Fore.BLACK + piece.symbol if piece.color == "black" else '.' for piece in self.board.get_row(row)]))

    def make_move(self, from_pos, to_pos):
        current_player = self.players[self.current_player]
        move_result = current_player.move(from_pos, to_pos)
        if not move_result:
            click.echo("Invalid move. Please try again.")
        else:
            self.board.update(move_result)

    def switch_turn(self):
        self.current_player = 1 - self.current_player

    def check_winner(self):
        return self.board.check_winner()
```

#### `board.py`
```python
from piece import Piece, WHITE, BLACK

class Board:
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        pieces = [WHITE, BLACK]
        for row in range(8):
            for col in range(8):
                if (row + col) % 2 == 1:
                    self.grid[row][col] = Piece(pieces[(row < 3) - (row > 4)])

    def get_row(self, row):
        return self.grid[row]

    def update(self, move):
        from_pos, to_pos, jump = move
        piece = self.grid[from_pos[0]][from_pos[1]]
        self.grid[to_pos[0]][to_pos[1]] = piece
        self.grid[from_pos[0]][from_pos[1]] = None
        if jump:
            mid_piece = self.grid[(from_pos[0] + to_pos[0]) // 2][(from_pos[1] + to_pos[1]) // 2]
            self.grid[(from_pos[0] + to_pos[0]) // 2][(from_pos[1] + to_pos[1]) // 2] = None
        if to_pos[0] == 0 and piece.color == "white" or to_pos[0] == 7 and piece.color == "black":
            self.grid[to_pos[0]][to_pos[1]] = Piece(piece.color, True)

    def check_winner(self):
        return any([row.count(None) == 8 for row in self.grid])
```

