from enum import Enum

class Color(Enum):
    WHITE = "white"
    BLACK = "black"

WHITE = Color.WHITE
BLACK = Color.BLACK

class Piece:
    def __init__(self, color: Color, kinged=False):
        self.color = color
        self.kinged = kinged

    @property
    def symbol(self):
        if self.color == WHITE and not self.kinged:
            return 'WK'
        elif self.color == BLACK and not self.kinged:
            return 'BK'
        elif self.color == WHITE and self.kinged:
            return 'WQ'
        else:
            return 'BQ'
```

