from board import Board, Piece

class Player:
    def __init__(self, color):
        self.color = color

    def move(self, from_pos, to_pos):
        if not 0 <= from_pos[0] < 8 or not 0 <= from_pos[1] < 8 or not 0 <= to_pos[0] < 8 or not 0 <= to_pos[1] < 8:
            return False

        piece = Board.grid[from_pos[0]][from_pos[1]]
        if piece is None or piece.color != self.color:
            return False

        if (to_pos[0] - from_pos[0], to_pos[1] - from_pos[1]) in [(1, 1), (-1, 1)]:
            Board.grid[to_pos[0]][to_pos[1]] = piece
            Board.grid[from_pos[0]][from_pos[1]] = None
            return (from_pos, to_pos, False)

        if (to_pos[0] - from_pos[0], to_pos[1] - from_pos[1]) in [(2, 2), (-2, 2)]:
            jump_piece = Board.grid[(from_pos[0] + to_pos[0]) // 2][(from_pos[1] + to_pos[1]) // 2]
            if jump_piece is not None and jump_piece.color != self.color:
                Board.grid[to_pos[0]][to_pos[1]] = piece
                Board.grid[from_pos[0]][from_pos[1]] = None
                Board.grid[(from_pos[0] + to_pos[0]) // 2][(from_pos[1] + to_pos[1]) // 2] = None
                return (from_pos, to_pos, True)

        return False
```

